// RSS 來源清單：要加來源只要在這裡加一行
return [
  { json: { url: "https://www.mlbtraderumors.com/san-francisco-giants/feed" } },
  { json: { url: "https://www.mlb.com/feeds/news/rss.xml?team_id=137" } },
  { json: { url: "https://www.mccoveychronicles.com/rss/index.xml" } },
  { json: { url: "https://news.google.com/rss/search?q=%22San+Francisco+Giants%22+site:sfchronicle.com&hl=en-US&gl=US&ceid=US:en" } },
  { json: { url: "https://www.nbcsportsbayarea.com/mlb/san-francisco-giants/feed/" } },
  { json: { url: "https://www.mercurynews.com/sports/mlb/san-francisco-giants/feed/" } },
  { json: { url: "https://sfstandard.com/category/sports/feed/" } },
  { json: { url: "https://www.nytimes.com/athletic/rss/mlb/sf-giants/" } }
];

// 依連結網域標記來源，並對綜合型來源（SF Standard）做關鍵字預過濾
const sourceMap = [
  [/mlbtraderumors\.com/i, 'MLBTR'],
  [/mlb\.com/i, 'MLB.com'],
  [/mccoveychronicles\.com/i, 'McCovey Chronicles'],
  [/nbcsportsbayarea\.com/i, 'NBC Sports Bay Area'],
  [/mercurynews\.com/i, 'Mercury News'],
  [/sfstandard\.com/i, 'SF Standard'],
  [/nytimes\.com|theathletic\.com/i, 'The Athletic'],
  [/news\.google\.com|sfchronicle\.com/i, 'SF Chronicle']
];

const out = [];
for (const item of items) {
  const j = item.json;
  const link = j.link || '';
  if (!link || !j.title) continue;

  let source = '其他';
  for (const [re, name] of sourceMap) {
    if (re.test(link)) { source = name; break; }
  }

  // SF Standard 是綜合體育版，先用關鍵字擋掉勇士/49人等非棒球內容，省 AI 成本
  if (source === 'SF Standard') {
    const text = `${j.title} ${j.contentSnippet || ''}`;
    if (!/giants/i.test(text)) continue;
  }

  out.push({ json: { ...j, source } });
}
return out;

// 為每篇文章組出 AI 評估用的 prompt，並保留後續需要的欄位
return items.map(item => {
  const j = item.json;
  const snippet = (j.contentSnippet || j.content || '').replace(/\s+/g, ' ').slice(0, 800);
  const aiPrompt = `文章標題：${j.title}\n來源：${j.source}\n摘要片段：${snippet}\n\n請評估這篇文章。`;
  return {
    json: {
      title: j.title,
      link: j.link,
      source: j.source,
      pubDate: j.isoDate || j.pubDate || '',
      aiPrompt
    }
  };
});

