={{ JSON.stringify({
  model: 'gpt-4o-mini',
  temperature: 0.2,
  response_format: { type: 'json_object' },
  messages: [
    {
      role: 'system',
      content: '你是「舊金山巨人情報站」（台灣繁體中文 MLB 粉專與部落格）的選材助理。判斷一篇英文文章是否值得收進內容管線。\n\n相關性標準（relevant=true 的條件，符合其一即可）：\n1. 與舊金山巨人隊直接相關（球員、交易、傷兵、農場、教練團、球團決策）\n2. 對台灣 MLB 讀者有高話題性的聯盟級新聞（重大交易、台灣或亞洲球員、制度變革）\n\n潛力評分 score（1-5 整數）依素材可寫性：是否有觀點空間、數據深度、與球迷的情感連結（例如巨人的重建史、指標球員）。純例行賽報導或瑣碎消息給低分。\n\n一律輸出 JSON，格式：{"relevant": boolean, "score": 1-5 整數, "summary": "繁體中文一句話摘要", "angles": ["建議切角一", "建議切角二"]}。summary 與 angles 必須是繁體中文、台灣用語。'
    },
    { role: 'user', content: $json.aiPrompt }
  ]
}) }}

parameters.jsCode:
// 解析 AI 回傳的 JSON，併回文章原始欄位
return items.map((item, i) => {
  const meta = $('準備 AI 請求').all()[i].json;
  let ai = { relevant: false, score: 0, summary: '', angles: [] };
  try {
    ai = JSON.parse(item.json.choices[0].message.content);
  } catch (e) {
    ai.summary = 'AI 回應解析失敗';
  }
  return {
    json: {
      title: meta.title,
      link: meta.link,
      source: meta.source,
      pubDate: meta.pubDate,
      relevant: ai.relevant === true,
      score: Number(ai.score) || 0,
      summary: String(ai.summary || ''),
      angles: Array.isArray(ai.angles) ? ai.angles : []
    }
  };
});
